#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, target;
    cin >> n >> target;

    vector<int> arr(n);
    for (int i = 0; i < n; ++i) {
        cin >> arr[i];
    }

    long long max_prod = -1;
    int res1 = -1, res2 = -1;
    bool found = false;

    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (arr[i] + arr[j] == target) {
                long long current_prod = (long long)arr[i] * arr[j];
                if (!found || current_prod > max_prod) {
                    max_prod = current_prod;
                    res1 = arr[i];
                    res2 = arr[j];
                    found = true;
                }
            }
        }
    }

    if (!found) {
        cout << -1 << endl;
    } else {
        if (res1 > res2) {
            cout << res1 << " " << res2 << endl;
        } else {
            cout << res2 << " " << res1 << endl;
        }
    }
    return 0;
}

