        scanf("%d", &arr[i]);
    }

    long long max_prod = -1;
    int res1 = -1, res2 = -1;
    int found = 0;

    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (arr[i] + arr[j] == target) {
                long long current_prod = (long long)arr[i] * arr[j];
                if (!found || current_prod > max_prod) {
                    max_prod = current_prod;
                    res1 = arr[i];
                    res2 = arr[j];
                    found = 1;
                }
            }
        }
    }

    if (!found) {
        printf("-1\n");
