import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main (String[] args) throws java.lang.Exception {
        Scanner sc = new Scanner(System.in);

        int n = sc.nextInt();
        int target = sc.nextInt();

        int[] arr = new int[n];
        for (int i = 0; i < n; i++) {
            arr[i] = sc.nextInt();
        }

        long maxProd = -1;
        int res1 = -1, res2 = -1;
        boolean found = false;

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (arr[i] + arr[j] == target) {
                    long currentProd = (long)arr[i] * arr[j];
                    if (!found || currentProd > maxProd) {
                        maxProd = currentProd;
                        res1 = arr[i];
                        res2 = arr[j];
                        found = true;
                    }
                }
            }
        }

        if (!found) {
            System.out.println(-1);
        } else {
            if (res1 > res2) {
                System.out.println(res1 + " " + res2);
            } else {
                System.out.println(res2 + " " + res1);
            }
        }
    }
}

